  ('real-estate-moex-01492', 'real-estate', 'real-estate-moex-104-ec2e292a', 'sub-real-estate-02', NULL, 'single_choice', '依公寓大廈管理條例之規定，公寓大廈專有部分之共同壁及樓地板或其內之管線，其維修費用如何負擔？', '["由維修之區分所有權人負擔", "由維修之住戶負擔", "由該共同壁雙方或樓地板上下方之區分所有權人共同負擔", "由該共同壁雙方或樓地板上下方之住戶共同負擔"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:09+00:00", "source_pdf_sha1": "6f4a35537845", "answer_pdf_sha1": "63f780aa7d6e", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1103", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "不動產經紀相關法規概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
